import supabase from "./supabase.js";

// ── Vote toggle ──
export const toggleVoteService = async (storyId, userId) => {
    if (!storyId || !userId) {
        throw { status: 400, error: 'storyId and userId are required' };
    }

    const { data: existing } = await supabase
        .from('story_votes')
        .select('id')
        .eq('story_id', storyId)
        .eq('user_id', userId)
        .maybeSingle();

    if (!existing) {
        const [insertRes, countRes] = await Promise.all([
            supabase.from('story_votes').insert({ story_id: storyId, user_id: userId }),
            supabase.from('stories').update({ vote_count: supabase.rpc ? undefined : 0 }).eq('id', storyId),
        ]);
        // Increment vote_count via raw update
        await supabase.rpc('increment_story_votes', { sid: storyId, delta: 1 }).catch(() => {
            // Fallback: manual increment
            supabase.from('stories').select('vote_count').eq('id', storyId).single().then(({ data }) => {
                if (data) supabase.from('stories').update({ vote_count: (data.vote_count || 0) + 1 }).eq('id', storyId);
            });
        });

        if (insertRes.error) {
            console.error('supabase error inserting vote:', insertRes.error.message);
            throw { status: 500, error: 'failed to vote' };
        }
        return { message: 'voted' };
    } else {
        const { error } = await supabase
            .from('story_votes')
            .delete()
            .eq('story_id', storyId)
            .eq('user_id', userId);

        // Decrement vote_count
        await supabase.rpc('increment_story_votes', { sid: storyId, delta: -1 }).catch(() => {
            supabase.from('stories').select('vote_count').eq('id', storyId).single().then(({ data }) => {
                if (data) supabase.from('stories').update({ vote_count: Math.max(0, (data.vote_count || 0) - 1) }).eq('id', storyId);
            });
